class Solution:
    def checkPalindromeFormation(self, a: str, b: str) -> bool:
        n = len(a)
        for i in range(n):
            if a[:i] + a[i:] == a[:i][::-1] + a[i:][::-1]:
                return True
            if b[:i] + b[i:] == b[:i][::-1] + b[i:][::-1]:
                return True
            if a[:i] + b[i:] == (a[:i] + b[i:])[::-1]:
                return True
            if b[:i] + a[i:] == (b[:i] + a[i:])[::-1]:
                return True
        return False
